import './styles/main.scss';
import { initNavigation } from './navigation';
import { initSearch } from './search';
import { initMermaid } from './mermaid';
import { initLightbox } from './lightbox';
import { initInterviewPrep } from './interviewPrep';
import { initTechMemory } from './techMemory';
import { initThreeViewer } from './threeViewer';

const DATA_BASE_ATTR = 'data-base-url';

function getBaseUrl(): string {
  const el = document.body;
  if (!el) return '';
  const value = el.getAttribute(DATA_BASE_ATTR);
  if (!value) return '';
  return value.endsWith('/') ? value.slice(0, -1) : value;
}

function ready(fn: () => void): void {
  if (document.readyState === 'complete' || document.readyState === 'interactive') {
    fn();
    return;
  }
  document.addEventListener('DOMContentLoaded', fn, { once: true });
}

ready(() => {
  const baseUrl = getBaseUrl();

  initNavigation({ baseUrl });
  initSearch({ baseUrl });
  initMermaid();
  initLightbox();
  initInterviewPrep();
  initTechMemory();
  initThreeViewer();
});
